//2009-06-25 YHS 확인

scwin.popUpEvent = function() {
    Link.tranCd = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranCd");
    Link.ogtranYMS = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "ogtranYMS");
    Link.cnclRstrInfoCtnt = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclRstrInfoCtnt"); // by.yyg 20090704
    Link.cupldTranDstcd = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cupldTranDstcd"); // by.leecj 20090813
    Link.ogtranGUID = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "ogtranGuid"); // by.yyg 20090704
    Link.acno = acno.getValue();
    Link.tranYmd = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranDte");
    Link.acnStus = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "acnStus");
    Link.tranName = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranName");
    Link.tranNoacc = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranNoacc");
    Link.tranTtm = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranTtm");
    Link.rmandrNoacc = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "rmandrNoacc");
    Link.tranAmt = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranAmt");
    Link.csh = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "csh");
    Link.trfer = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "trfer");
    Link.chek = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "chek");
    Link.rpurchFee = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "rpurchFee");
    Link.txbfValpr = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "valpr");
    Link.idtrek = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "idtrek");
    Link.hndlnBrn = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "prcssBrncd");
    Link.trmno = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "trmno");
    Link.slipNo = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "slipNo");
    Link.chnlDstic = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "chnlDstic");
    Link.mdiaDstic = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "mdiaDstic");
    Link.tranEmpid = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranEmpid");
    Link.cnclYn = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclYn"); // 그리드내 취소구분 추가(2013.10.28)
    $c.iz.screen.popup("KFG04202001", "DATALINK");
};

// 취소버튼 클릭 시 이벤트
scwin.Button1_OnClick = function(e) {
    //취소
    // 조회된 데이터가 없으면 에러처리
    if (dataDvsn.getTotalRow() == 0) {
        $c.iz.data.alert("취소대상거래가 없습니다.", "오류");
        return;
    }
    if (dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "selct") == "N") // 선택안됨

    {
        $c.iz.data.alert("선택된 거래가 없습니다.", "오류");
        return;
    }

    // 채널구분이 05(센터컷)인 경우 단말취소가 불가능하므로 에러처리
    var channel = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "chnlDstic");
    var test1 = channel.substring(0, 2);
    var tranEmpid = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranEmpid");
    //	var cnclRstrInfoCtnt  = dataDvsn.GetCellDataSaveName(dataDvsn.GetSelectRow(), "cnclRstrInfoCtnt");	 
    var TranName = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranName");
    var cnclCTranAbilYn = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclCTranAbilYn");
    if (channel.substring(0, 2) == '05') {
        // 채널구분이 05(센터컷)인 경우 자동이체만 창구취소 허용 + 목표도달자동환매 창구취소허용 (JITKB)
        // + 펀드정기지급서비스 창구취소허용 20181128
        if (tranEmpid.substring(0, 7) == 'C301301' || tranEmpid.substring(0, 7) == 'C372101' || tranEmpid.substring(0, 7) == 'C324352' || tranEmpid.substring(0, 7) == 'C340139') {

        } else {
            // 2015.10.01 C340103, C340110, C340111 입금예약분 취소 추가
            if ((tranEmpid.substring(0, 7) == 'C340103' || tranEmpid.substring(0, 7) == 'C340110' || tranEmpid.substring(0, 7) == 'C340111') && tranName.substring(0, 4) == 'N102') {

            } else {
                //20190131 연금일괄매매예약 취소 가능  
                if ((tranEmpid.substring(0, 7) == 'C340137' && (tranName.substring(0, 4) == 'N910' || tranName.substring(0, 4) == 'N202')) || /* 출금/해약 예약 취소 */
                    (tranEmpid.substring(0, 7) == 'C340136' && (tranName.substring(0, 4) == 'N102')) || /* 입금예약 취소 */
                    (tranEmpid.substring(0, 7) == 'C340137' && tranName.substring(0, 4) == 'N301')) {
                    //

                } else {
                    $c.iz.data.alert("센터컷 거래는 창구에서 단말취소 할수 없습니다.", "오류");
                    return;
                }
            }
        }
    } else if (channel.substring(0, 2) == '01') {
        var prcssBrncd = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "prcssBrncd");
        if (prcssBrncd.substring(0, 4) == '1117') {
            //1117
            $c.iz.data.alert("본부 일부상환출금예약 거래는 단말취소 할수 없습니다.", "오류");
            return;
        }
        if (tranName.substring(0, 4) == 'N910' && cnclCTranAbilYn == '0') {
            $c.iz.data.alert("취소 불가능한 거래입니다.", "오류");
            return;
        }
    }


    // 이미 취소된 거래를 다시 취소버튼 클릭시 오류(2013.10.28)	
    var wkcnclYn = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclYn").substring(0, 1); // 그리드내 취소구분
    if (wkcnclYn != '0') {
        $c.iz.data.alert("이미 취소된 거래는 취소가 불가능합니다.", "오류");
        return;
    }

    // 시스템현재날짜와 취소대상거래년월일(tranYmd)이 다르면 (취소대상거래가 현재일이 아니면) 에러처리	
    var tranymd = $c.user.getUserProfile('nowBzoprYmd'); // 영업일
    var seltrandt = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranDte"); // 선택거래년월일
    if (tranymd == seltrandt) {
        //취소구분코드 9 (취소) 셋
        Link.cnclCd = "9";
        scwin.popUpEvent();
    } else {
        $c.iz.data.alert("당일취소거래가 아닙니다. 당일거래만 취소가능합니다", "오류");
    }
};

scwin.LinkText1_OnClick = function(e) {
    // 펀드코드를 넘김
    var tmp = '04';
    Link.KAF_fundCd = tmp.concat(fundCd.getValue());
