    $c.iz.screen.screenOpen("KAF04706000", "DATALINK");
};

scwin.LinkText2_OnClick = function(e) {
    // 지급계산서 발급
    if (dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "selct") == "N") // 선택안됨

    {
        $c.iz.data.alert("선택된 거래가 없습니다.", "오류");
        return;
    }

    // 선택된 거래가 출금이 아니면 지급계산서 발급 버튼클릭 안됨
    var strTranName = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranName");
    if (strTranName.length > 4) {
        if (strTranName.substring(0, 4) == 'N201' || strTranName.substring(0, 4) == 'N203' ||
            strTranName.substring(0, 4) == 'N205' || strTranName.substring(0, 4) == 'N206' ||
            strTranName.substring(0, 4) == 'N302' || strTranName.substring(0, 4) == 'N209' ||
            strTranName.substring(0, 4) == 'N211' ||
            strTranName.substring(0, 4) == 'N213' || strTranName.substring(0, 4) == 'N215') {

        } else {
            $c.iz.data.alert("지급계산서 발급 대상이 아닙니다.", "오류");
            return;
        }
    }
    var strTranDte = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranDte");
    var strTranNo = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranNo");
    // 계좌번호를 넘김
    Link.acno = acno.getValue();
    // 거래일자를 넘김
    Link.tranDte = strTranDte;
    // 거래번호를 넘김
    Link.tranNo = strTranNo;
    // Link.
    $c.iz.screen.screenOpen("KFG04211000", "DATALINK");
};

scwin.LinkText3_OnClick = function(e) {
    // 출금상세내역조회
