                strTranName.substring(0, 4) == 'N103' || strTranName.substring(0, 4) == 'N106' ||
                strTranName.substring(0, 4) == 'N112' || strTranName.substring(0, 4) == 'N110') {
                Link.tranDstic = "1";
            } else {
                Link.tranDstic = "2";
            }
        } else {
            $c.iz.data.alert("자계좌상세내역조회 대상이 아닙니다.", "오류");
            return;
        }
    }

    // Link.
    $c.iz.screen.screenOpen("KFG04260000", "DATALINK");
};

// 그리드출력필드 클릭 시 이벤트
scwin.dataDvsn_OnDClick = function(Arg1, Arg2, Arg3) {
    // 그리드필드 8번째 항목 (연동정보)필드 클릭 시 연동정보팝업 실행
    if (Arg2 == 8) {
        // 연동정보가 0 (해당무)이면 연동정보가 팝업을 안띄움
        var cupldinfo = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cupldTranDstcd");
        if (cupldinfo == '0') {
            $c.iz.data.alert("연동정보가 없습니다.", "오류");
            return;
        }
        Link.TranCd = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranCd");
        Link.CupldTranDstcd = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cupldTranDstcd");
        Link.CnclRstrInfo = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclRstrInfoCtnt");
        // 연동정보팝업 실행
        $c.iz.screen.popup("KHD04005000", "DATALINK");
    } else {
        //Link.cnclCd = "2";
        // 거래내역상세조회 팝업실행
        // 취소구분코드 = 0(정상)으로 셋
        Link.cnclCd = "0";
        scwin.popUpEvent();
    }
};


scwin.OnInitScreen = function() {
    //여기에 구현코드를 삽입하세요.
    $c.iz.tran.setSendKey(1);
    acno.focus();
    inquryEndYmd.setValue($c.user.getUserProfile('nowBzoprYmd'));
    inquryStartYmd.setValue($c.com.getAccDate($c.user.getUserProfile('nowBzoprYmd'), -6, "M"));
    receiptDstic.setValue('0'); //20100326 김소영- 확인서인자 1, 그냥 조회 0 
    fundAttriDstcd.setValue(' ');

    //20170801 김소영
    Button1.show('');
    Button1.setDisabled(false);
    Button_correct.hide();
    Button_correct.setDisabled(true);
    edt_mrv_Amt.setValue(0); //20170725 데이터삭제
};


scwin.OnSendKey2 = async function() {
    // next key로 송신시 조회조건이 변경되었는지를 체크하기 위함.	
    scwin.bfAcno = acno.getValue();
    scwin.bfStartYmd = inquryStartYmd.getValue();
    scwin.bfEndYmd = inquryEndYmd.getValue();
    scwin.bfLnpMod = lnpMod.getValue();
    //alert(" bfLnpMod  "+bfLnpMod," ");
    nextKey.setValue(""); // NextKey초기화    
    dataDvsn.removeAll(); // grid 삭제 초기화
    GroupBox2.setValue(""); // groupbox 데이터초기화

    var iDecimalPoint;
    var iAmtDecimalPoint;
    $c.iz.tran.setTranID("KFG0420241");
    // 55과목 or 24과목이 아니면 에러처리
    var stracno = acno.getValue();
    var acnolen = stracno.length;
    // 계좌번호가 14 && 과목코드가 55, 24가 아니면 오류팝업
    if (acnolen == 14 && acno.getValue().substring(4, 6) != "55" && acno.getValue().substring(4, 6) != "24") {
        $c.iz.data.alert("펀드계좌만 조회가능합니다.", "오류");
        return;
    }
    if (acno.getValue().substring(4, 6) == "24") {
        iDecimalPoint = 3; //좌수
        iAmtDecimalPoint = 2; //금액
    } else {
        iDecimalPoint = 0;
        iAmtDecimalPoint = 0;

    } /*ORG SRC: dataDvsn.DataDispDecimalPoint(1, dataDvsn.GetSaveNameCol("tranNoacc")) = iDecimalPoint; //거래좌수*/ // ✖ = iDecimalPoint; //거래좌수

    /*ORG SRC: dataDvsn.DataDispDecimalPoint(1, dataDvsn.GetSaveNameCol("tranAmt")) = iAmtDecimalPoint; //거래금액*/
    // ✖ = iAmtDecimalPoint; //거래금액

    /*ORG SRC: dataDvsn.DataDispDecimalPoint(1, dataDvsn.GetSaveNameCol("rmandrNoacc")) = iDecimalPoint; //잔고좌수*/
    // ✖ = iDecimalPoint; //잔고좌수

    /*ORG SRC: dataDvsn.DataDispDecimalPoint(1, dataDvsn.GetSaveNameCol("valpr")) = iAmtDecimalPoint; //평가금액*/
    // ✖ = iAmtDecimalPoint; //평가금액

    /*ORG SRC: dataDvsn.DataDispDecimalPoint(1, dataDvsn.GetSaveNameCol("fee")) = iAmtDecimalPoint; //수수료*/
    // ✖ = iAmtDecimalPoint; //수수료

    /*ORG SRC: dataDvsn.DataDispDecimalPoint(1, dataDvsn.GetSaveNameCol("trfer")) = iAmtDecimalPoint; //대체*/
