scwin.OnEndTran = function() {
    receiptDstic.setValue('0'); //20100326 김소영- 확인서인자 1, 그냥 조회 0  
    dataDvsn.setCellData(dataDvsn.getFocusedRowIndex(), "selct", 'N'); //20100326 김소영 확인서 인자 후 체크 선택 해제 

    //여기에 구현코드를 삽입하세요.
    if ($c.iz._tran.bError) {
        Button_receipt.setDisabled(true);
        Button_correct.setDisabled(true); //20170725 정정버튼도비활성화처리 
        edt_mrv_Amt.setValue(0); //20170725 데이터삭제
        return;
    }
    if ($c.iz._tran.tranId == "KFG0420241") {
        //20170801 모집식펀드일 경우 취소버튼-->정정버튼
        edt_mrv_Amt.setValue(0); //20170725 데이터삭제
        var tranymd = $c.user.getUserProfile('nowBzoprYmd'); // 영업일
        var seltrandt = dataDvsn.getCellData(1, "tranDte"); // 선택거래년월일 	    

        if (ofernStylYn.getValue() == '1' && (tranymd != seltrandt)) {
            Button1.hide(); //취소버튼
            Button1.setDisabled(true);
            Button_correct.show(''); //정정버튼 
            Button_correct.setDisabled(false);

            //20170801 정정처리금액(매입금액 + 수수료)
            edt_mrv_Amt.setValue(Number(dataDvsn.getCellData(2, "trfer")) + Number(dataDvsn.getCellData(2, "csh")));
        } else {
            Button1.show('');
            Button1.setDisabled(false);
            Button_correct.hide();
            Button_correct.setDisabled(true);
        }
    }

    // 고객번호 패턴변경 - 시작

    /* 20170801_start 현재 AAAAA-AAAAA 이 패턴만 사용함
    var strPattern = "AAAAA-AAAAA";	    //고객식별자(20150204)
    var strPattern1 = "AAAAAA-AA*****"
    var strPattern2 = "AAAAAAAAAAAAA"
    var strPattern3 = "AAA-AA-*****"	
    var strCustNo = " ";
    var strCustNo = Tran.GetOutFDData("KFG0420241", "screen", "custNo");	// 고객번호			
    custno.SetPattern(strPattern);        //고객식별자(20150204)  	
    20170801_end */

    /* 20170801 이전 주석처리_start 
	var len = strCustNo.length;

    var i = 0;        
    while( i < len && strCustNo.substr(i, 1)== " " )
    {    	    	
        i ++;       
    }
    strCustNo = strCustNo.substr( i , len - i);

	if(strCustNo.length == 13)	// 내국인 주민번호
	{
		custno.SetPattern(strPattern1);
	}
	else if(strCustNo.length == 10)	// 사업자번호
	{
		custno.SetPattern(strPattern3);
	}
	else
	{
		custno.SetPattern(strPattern2);
	}
	20170801 이전 주석처리_end
	*/

    //custno.Value = strCustNo; 20170801 

