// 20100326 예탁금보관 확인서 인자 버튼 추가
scwin.Button_receipt_OnClick = async function(e) {
    // 거래구분이 입금예약인 경우 선택 시 버튼 활성화 및 인자 
    if (dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "selct") == "N") // 선택안됨

    {
        $c.iz.data.alert("선택된 거래가 없습니다.", "오류");
        return;
    }
    if (dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranDte") < 20100216) // 2010년 2월 16일 이후 거래만 가능

    {
        $c.iz.data.alert("2010년 2월 16일 이후만 예탁금 보관 확인서 인자가 가능합니다.", "오류");
        return;
    }
    var compText = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranName").substring(0, 4);
    if (compText != "N102" && compText != "N106" && compText != "N110" && compText != "N112") // 입금예약 선택 아닐때 

    {
        $c.iz.data.alert("입금예약일 때 만 예탁금 보관 확인서 인자가 가능합니다.", "오류");
        return;
    }
    var canText = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclYn").substring(0, 1);
    if (canText != '0') {
        $c.iz.data.alert("취소 거래는 예탁금 보관 확인서 인자가 불가능합니다.", "오류");
        return;
    }
    var subjText = acno.getValue().substring(4, 6);
    //  박재규 subjText에서 ->fundAttriDstcd.Data(펀드속성코드)로 변경함	
    //	if ( subjText == '24' )
    if (fundAttriDstcd.getValue() == '3') //역외코드

    {
        //2010.12.10 shkim		alert("해외 펀드 계좌는 예탁금 보관 확인서 인자가 불가능합니다.", "오류");
        $c.iz.data.alert("역외 펀드 계좌는 예탁금 보관 확인서 인자가 불가능합니다.", "오류");
        return;
    }
    $c.iz.tran.setTranID("KFG0420241");
    await $c.iz.tran.ASend();
};

//20100326 김소영 row 선택 시 확인서 인자를 위한 입력 값 셋팅 및 버튼 활성화 제어
scwin.dataDvsn_OnClick = function(Arg1, Arg2, Arg3) {
    var compText = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranName").substring(0, 4); // 거래명
    var canText = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclYn").substring(0, 1); //취소여부
    var subjText = acno.getValue().substring(4, 6); //과목코드
    var dateText = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranDte"); //거래일자

    GroupBox4.setValue(""); //입력 값 초기화 
    // 입금예약,기일예약,이전입금예약,WISE입금예약 정상(취소아님),국내수익증권펀드, 차세대 오픈 날 이후 거래  
    // 골든라이프연금 모계좌는 투자자예탁금확인서 발급 불가(자펀드마다 예탁 보관일수가 상이 할수 있음)
    // --> 자계좌별로 투자자예탁금확인서 인자할것 (2014.07.25)
    if (Arg2 == 0 && dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "selct") == "Y" &&
        (compText == "N102" || compText == "N106" || compText == "N110" || compText == "N112") &&
        //  박재규 subjText에서 ->fundAttriDstcd.Data(펀드속성코드)로 변경함		    
        //		&& canText == '0' && subjText =='55' 
        canText == '0' && (fundAttriDstcd.getValue() == '1' || fundAttriDstcd.getValue() == '2' || fundAttriDstcd.getValue() == '4') &&
        dateText >= '20100216' && fundCd.getValue().substring(2, 5) != '900') {
        cnfCustnm.setValue(custnm.getValue()); //고객명 		
        cnfFundDstic.setValue(fundCd.getValue()); //펀드코드	

        //입금금액
        cnfMrvamt.setValue(Number(dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "trfer")) + Number(dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "csh"))); //펀드명		

        tranDte.setValue(dateText);
        tranNo.setValue(dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranNo")); //거래번호
        cnclDstic.setValue(canText); // 취소구분
        custOgNo.setValue(custno.getValue());
        Button_receipt.setDisabled(false);

        //인자 구분자 셋팅 
        receiptDstic.setValue('1'); //20100326 김소영- 확인서인자 1, 그냥 조회 0  
    } else {
        Button_receipt.setDisabled(true);
        receiptDstic.setValue('0'); //20100326 김소영- 확인서인자 1, 그냥 조회 0  
    }
};

