//20170801 모집식펀드 정정처리
scwin.Button_correct_OnClick = async function(e) {
    //여기에 구현코드를 삽입하세요.

    // 조회된 데이터가 없으면 에러처리
    if (dataDvsn.getTotalRow() == 0) {
        $c.iz.data.alert("정정대상거래가 없습니다.", "오류");
        return;
    }
    if (dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "selct") == "N") // 선택안됨

    {
        $c.iz.data.alert("선택된 거래가 없습니다.", "오류");
        return;
    }

    // 이미 취소된 거래를 다시 취소버튼 클릭시 오류
    var wkcnclYn = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "cnclYn").substring(0, 1); // 그리드내 취소구분
    /*
     * 2019.11.26 계좌해지된 계좌는 정정처리 불가
     * 선택한 거래는 정상인데 계좌상태는 해지된 계좌이면 정정처리 불가
     */
    if (wkcnclYn == '0') {
        var headerRowCnt = dataDvsn.getHeaderRows();
        for (var i = headerRowCnt; i < (dataDvsn.getTotalRow() + headerRowCnt); i++) {
            // 계좌해지 거래가 있으면
            if (wkcnclYn == '0' && dataDvsn.getCellData(i, "tranName").substr(0, 4) == "N301") {
                // 취소여부(구분) 변경
                wkcnclYn = 'Z';
            }
        }
    }
    if (wkcnclYn != '0') {
        $c.iz.data.alert("이미 정정된 거래는 정정처리가 불가능합니다.", "오류");
        return;
    }

    /*
     * 2019.11.26 정정거래시 외화모집식펀드는 16:00:00 이후 거래 불가
     * 펀드계좌의 과목코드가 '024'이면 체크함
     */
    if (acno.getValue().substring(4, 6) == "24" && Number($c.com.getTime()) > 160000) {
        $c.iz.data.alert("외화모집식펀드 정정거래는 16시 이후 거래가 불가능합니다.", "오류");
        return;
    }
    var seltrandt = dataDvsn.getCellData(dataDvsn.getFocusedRowIndex(), "tranDte"); // 선택거래년월일    

    //정정처리금액(매입금액 + 수수료)
    edt_mrv_Amt.setValue(Number(dataDvsn.getCellData(2, "trfer")) + Number(dataDvsn.getCellData(2, "csh")));
    $c.iz.tran.setTranID("KFG0100112");
    $c.iz.tran.setInFDData("KFG0100112", "tranDstic", "08"); //거래구분 : 모집식정정 처리 
    $c.iz.tran.setInFDData("KFG0100112", "mnrcvDstic", mnrcvDstic.getValue()); //입금구분 : 2.연결계좌이체  4.MMF계좌에서 이체
    $c.iz.tran.setInFDData("KFG0100112", "tranAmtInfo/rceitDstic1", "09"); //수납구분(09:대체)		
    $c.iz.tran.setInFDData("KFG0100112", "acnInfo/tranYmd", seltrandt); //거래년월일
    $c.iz.tran.setInFDData("KFG0100112", "acnInfo/tranSerno", 2); //거래일련번호
    await $c.iz.tran.ASend();
};
